            failedChecks.append("Code signature validation failed")
        }
        
        // Check 7: Sandbox integrity
        if !checkSandboxIntegrity() {
            suspiciousIndicators.append("Sandbox integrity compromised")
        }
        
        let isCompromised = !failedChecks.isEmpty
        let riskLevel: RiskLevel = isCompromised ? .high : (suspiciousIndicators.isEmpty ? .low : .medium)
        
        return DeviceIntegrityResult(
            isCompromised: isCompromised,
            riskLevel: riskLevel,
            failedChecks: failedChecks,
            suspiciousIndicators: suspiciousIndicators
        )
    }
    
