    private func validateCodeSignature() -> Bool {
        guard let executablePath = Bundle.main.executablePath else {
            return false
        }
        
        var staticCode: SecStaticCode?
        let executableURL = URL(fileURLWithPath: executablePath) as CFURL
        
        let status = SecStaticCodeCreateWithPath(executableURL, [], &staticCode)
        guard status == errSecSuccess, let code = staticCode else {
            return false
        }
        
        let requirement: SecRequirement? = nil
        let validationStatus = SecStaticCodeCheckValidity(code, [], requirement)
        
        return validationStatus == errSecSuccess
    }
    
    private func checkSandboxIntegrity() -> Bool {
        let homeDir = NSHomeDirectory()
        return homeDir.contains("/var/mobile/Containers/")
