// MARK: - Secure API Communication

class SecureAPIClient {
    static let shared = SecureAPIClient()
    private let baseURL = "https://api.tradingplatform.com/v1"
    private let session: URLSession
    private let certificatePinner: CertificatePinner
    
    private init() {
        let configuration = URLSessionConfiguration.ephemeral
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.urlCache = nil
        configuration.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        
        self.certificatePinner = CertificatePinner()
        self.session = URLSession(configuration: configuration, delegate: certificatePinner, delegateQueue: nil)
    }
    
    func executeRequest<T: Decodable>(
        endpoint: String,
        method: HTTPMethod,
        body: Encodable? = nil,
        requiresAuth: Bool = true,
        completion: @escaping (Result<T, APIError>) -> Void
    ) {
        // Defense-in-depth: Check device integrity before sensitive operations
        let integrityResult = DeviceIntegrityManager.shared.performIntegrityChecks()
        
        if integrityResult.isCompromised {
            completion(.failure(.deviceIntegrityCompromised(details: integrityResult.failedChecks)))
            return
        }
        
        guard let url = URL(string: baseURL + endpoint) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Add security headers
        request.setValue(UUID().uuidString, forHTTPHeaderField: "X-Request-ID")
        request.setValue(String(Date().timeIntervalSince1970), forHTTPHeaderField: "X-Timestamp")
        
        if requiresAuth {
            guard let token = SecureTokenManager.shared.getAccessToken() else {
                completion(.failure(.unauthorized))
                return
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            do {
                request.httpBody = try JSONEncoder().encode(body)
                
                // Add request signature for integrity
                if let signature = signRequest(body: request.httpBody, timestamp: request.value(forHTTPHeaderField: "X-Timestamp") ?? "") {
                    request.setValue(signature, forHTTPHeaderField: "X-Signature")
                }
            } catch {
                completion(.failure(.encodingError))
                return
            }
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.networkError(error)))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.invalidResponse))
                return
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                if httpResponse.statusCode == 401 {
                    completion(.failure(.unauthorized))
                } else {
                    completion(.failure(.serverError(statusCode: httpResponse.statusCode)))
                }
                return
            }
            
            guard let data = data else {
                completion(.failure(.noData))
                return
            }
            
            do {
                let decoded = try JSONDecoder().decode(T.self, from: data)
                completion(.success(decoded))
            } catch {
                completion(.failure(.decodingError(error)))
            }
        }
        
        task.resume()
    }
    
    private func signRequest(body: Data?, timestamp: String) -> String? {
        guard let secret = SecureTokenManager.shared.getAPISecret(),
              let secretData = secret.data(using: .utf8) else {
            return nil
        }
        
        var dataToSign = Data()
        dataToSign.append(timestamp.data(using: .utf8) ?? Data())
        if let body = body {
            dataToSign.append(body)
        }
        
        return hmacSHA256(data: dataToSign, key: secretData)
    }
    
    private func hmacSHA256(data: Data, key: Data) -> String {
        var hmac = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { dataBytes in
            key.withUnsafeBytes { keyBytes in
                CCHmac(CCHmacAlgorithm(kCCHmacAlgSHA256), keyBytes.baseAddress, key.count, dataBytes.baseAddress, data.count, &hmac)
            }
        }
        return Data(hmac).base64EncodedString()
    }
}

