// MARK: - Trading Service

class TradingService {
    static let shared = TradingService()
    private let apiClient = SecureAPIClient.shared
    
    private init() {}
    
    func executeTrade(request: TradeRequest, completion: @escaping (Result<TradeResponse, APIError>) -> Void) {
        // Defense-in-depth: Additional integrity check for high-risk operation
        let integrityResult = DeviceIntegrityManager.shared.performIntegrityChecks()
        
        guard !integrityResult.isCompromised else {
            completion(.failure(.deviceIntegrityCompromised(details: integrityResult.failedChecks)))
            return
        }
        
        // Require biometric authentication for trades
        BiometricAuthManager.shared.authenticateUser(reason: "Authenticate to execute trade") { success, error in
            guard success else {
                completion(.failure(.unauthorized))
                return
            }
            
            self.apiClient.executeRequest(
                endpoint: "/trades/execute",
                method: .POST,
                body: request,
                requiresAuth: true,
                completion: completion
            )
        }
    }
    
    func getPortfolio(completion: @escaping (Result<Portfolio, APIError>) -> Void) {
        apiClient.executeRequest(
            endpoint: "/portfolio",
            method: .GET,
            requiresAuth: true,
            completion: completion
        )
    }
    
    func getTradeHistory(completion: @escaping (Result<[Trade], APIError>) -> Void) {
        apiClient.executeRequest(
            endpoint: "/trades/history",
            method: .GET,
            requiresAuth: true,
            completion: completion
        )
    }
    
    func getStockQuote(symbol: String, completion: @escaping (Result<Stock, APIError>) -> Void) {
        apiClient.executeRequest(
            endpoint: "/stocks/\(symbol)",
            method: .GET,
            requiresAuth: true,
            completion: completion
        )
    }
    
    func cancelTrade(tradeId: String, completion: @escaping (Result<TradeResponse, APIError>) -> Void) {
        apiClient.executeRequest(
            endpoint: "/trades/\(tradeId)/cancel",
            method: .POST,
            requiresAuth: true,
            completion: completion
        )
    }
}

// MARK: - Authentication Service

class AuthenticationService {
    static let shared = AuthenticationService()
    private let apiClient = SecureAPIClient.shared
    
    private init() {}
    
    func login(email: String, password: String, completion: @escaping (Result<LoginResponse, APIError>) -> Void) {
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? UUID().uuidString
        let request = LoginRequest(email: email, password: password, deviceId: deviceId)
        
        apiClient.executeRequest(
            endpoint: "/auth/login",
            method: .POST,
            body: request,
            requiresAuth: false
        ) { (result: Result<LoginResponse, APIError>) in
            switch result {
            case .success(let response):
                _ = SecureTokenManager.shared.saveAccessToken(response.accessToken)
                _ = SecureTokenManager.shared.saveRefreshToken(response.refreshToken)
                _ = SecureTokenManager.shared.saveAPISecret(response.apiSecret)
                completion(.success(response))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func logout() {
        SecureTokenManager.shared.clearAllTokens()
    }
    
    func isAuthenticated() -> Bool {
        return SecureTokenManager.shared.getAccessToken() != nil
    }
}

