        activityIndicator.startAnimating()
        loginButton.isEnabled = false
        
        AuthenticationService.shared.login(email: email, password: password) { [weak self] result in
            DispatchQueue.main.async {
                self?.activityIndicator.stopAnimating()
                self?.loginButton.isEnabled = true
                
                switch result {
                case .success:
                    self?.navigateToMainApp()
                case .failure(let error):
                    self?.handleLoginError(error)
                }
            }
        }
    }
    
    private func handleLoginError(_ error: APIError) {
        var message = "An error occurred during login"
        
        switch error {
        case .unauthorized:
            message = "Invalid email or password"
        case .deviceIntegrityCompromised(let details):
            message = "Device security check failed:\n" + details.joined(separator: "\n")
        case .networkError:
            message = "Network error. Please check your connection"
        default:
            message = "Login failed. Please try again"
        }
        
        showAlert(title: "Login Failed", message: message)
    }
    
    private func navigateToMainApp() {
        let tabBarController = MainTabBarController()
        if let window = view.window {
            window.rootViewController = tabBarController
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve, animations: nil)
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class MainTabBarController: UITabBarController {
    
