class PortfolioViewController: UIViewController {
    
    private var portfolio: Portfolio?
    
    private let tableView: UITableView = {
        let table = UITableView(frame: .zero, style: .grouped)
        table.translatesAutoresizingMaskIntoConstraints = false
        return table
    }()
    
    private let refreshControl = UIRefreshControl()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadPortfolio()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Portfolio"
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(title: "Logout", style: .plain, target: self, action: #selector(logoutTapped))
        
        view.addSubview(tableView)
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "Cell")
        tableView.refreshControl = refreshControl
        refreshControl.addTarget(self, action: #selector(refreshPortfolio), for: .valueChanged)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func loadPortfolio() {
        TradingService.shared.getPortfolio { [weak self] result in
            DispatchQueue.main.async {
                self?.refreshControl.endRefreshing()
                
                switch result {
                case .success(let portfolio):
                    self?.portfolio = portfolio
                    self?.tableView.reloadData()
                case .failure(let error):
                    self?.handleError(error)
                }
            }
        }
    }
    
    @objc private func refreshPortfolio() {
        loadPortfolio()
    }
    
    @objc private func logoutTapped() {
        AuthenticationService.shared.logout()
        
        let loginVC = LoginViewController()
        if let window = view.window {
            window.rootViewController = loginVC
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve, animations: nil)
        }
    }
    
    private func handleError(_ error: APIError) {
        var message = "Failed to load portfolio"
        
        if case .deviceIntegrityCompromised(let details) = error {
            message = "Security check failed:\n" + details.joined(separator: "\n")
        }
        
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension PortfolioViewController: UITableViewDelegate, UITableViewDataSource {
    
    func numberOfSections(in tableView: UITableView) -> Int {
        return 2
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        if section == 0 {
            return 3
        } else {
            return portfolio?.positions.count ?? 0
        }
    }
    
    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        return section == 0 ? "Summary" : "Positions"
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "Cell", for: indexPath)
        
        if indexPath.section == 0 {
            switch indexPath.row {
            case 0:
                cell.textLabel?.text = "Total Value: $\(portfolio?.totalValue ?? 0)"
            case 1:
                cell.textLabel?.text = "Cash Balance: $\(portfolio?.cashBalance ?? 0)"
            case 2:
                let gainLoss = portfolio?.totalGainLoss ?? 0
                let percent = portfolio?.totalGainLossPercent ?? 0
                cell.textLabel?.text = "Total Gain/Loss: $\(gainLoss) (\(percent)%)"
                cell.textLabel?.textColor = gainLoss >= 0 ? .systemGreen : .systemRed
            default:
                break
            }
        } else {
            if let position = portfolio?.positions[indexPath.row] {
                cell.textLabel?.text = "\(position.symbol): \(position.quantity) shares @ $\(position.currentPrice)"
                cell.detailTextLabel?.text = "P/L: $\(position.gainLoss) (\(position.gainLossPercent)%)"
            }
        }
        
        return cell
    }
}

class TradeViewController: UIViewController {
    
    private let symbolTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Stock Symbol (e.g., AAPL)"
        textField.borderStyle = .roundedRect
        textField.autocapitalizationType = .allCharacters
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let quantityTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Quantity"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .decimalPad
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let tradeTypeSegment: UISegmentedControl = {
        let segment = UISegmentedControl(items: ["Buy", "Sell"])
        segment.selectedSegmentIndex = 0
        segment.translatesAutoresizingMaskIntoConstraints = false
        return segment
    }()
    
    private let orderTypeSegment: UISegmentedControl = {
        let segment = UISegmentedControl(items: ["Market", "Limit"])
        segment.selectedSegmentIndex = 0
        segment.translatesAutoresizingMaskIntoConstraints = false
        return segment
    }()
    
    private let limitPriceTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Limit Price (optional)"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .decimalPad
        textField.isHidden = true
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let executeButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Execute Trade", for: .normal)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let currentPriceLabel: UILabel = {
        let label = UILabel()
        label.text = "Current Price: --"
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        checkDeviceIntegrity()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade"
        
        view.addSubview(symbolTextField)
        view.addSubview(currentPriceLabel)
        view.addSubview(quantityTextField)
        view.addSubview(tradeTypeSegment)
        view.addSubview(orderTypeSegment)
        view.addSubview(limitPriceTextField)
        view.addSubview(executeButton)
        
        NSLayoutConstraint.activate([
            symbolTextField.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            symbolTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            symbolTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            symbolTextField.heightAnchor.constraint(equalToConstant: 44),
            
            currentPriceLabel.topAnchor.constraint(equalTo: symbolTextField.bottomAnchor, constant: 10),
            currentPriceLabel.leadingAnchor.constraint(equalTo: symbolTextField.leadingAnchor),
            currentPriceLabel.trailingAnchor.constraint(equalTo: symbolTextField.trailingAnchor),
            
            quantityTextField.topAnchor.constraint(equalTo: currentPriceLabel.bottomAnchor, constant: 20),
            quantityTextField.leadingAnchor.constraint(equalTo: symbolTextField.leadingAnchor),
            quantityTextField.trailingAnchor.constraint(equalTo: symbolTextField.trailingAnchor),
            quantityTextField.heightAnchor.constraint(equalToConstant: 44),
            
            tradeTypeSegment.topAnchor.constraint(equalTo: quantityTextField.bottomAnchor, constant: 20),
            tradeTypeSegment.leadingAnchor.constraint(equalTo: symbolTextField.leadingAnchor),
            tradeTypeSegment.trailingAnchor.constraint(equalTo: symbolTextField.trailingAnchor),
            
            orderTypeSegment.topAnchor.constraint(equalTo: tradeTypeSegment.bottomAnchor, constant: 20),
            orderTypeSegment.leadingAnchor.constraint(equalTo: symbolTextField.leadingAnchor),
            orderTypeSegment.trailingAnchor.constraint(equalTo: symbolTextField.trailingAnchor),
            
            limitPriceTextField.topAnchor.constraint(equalTo: orderTypeSegment.bottomAnchor, constant: 20),
            limitPriceTextField.leadingAnchor.constraint(equalTo: symbolTextField.leadingAnchor),
            limitPriceTextField.trailingAnchor.constraint(equalTo: symbolTextField.trailingAnchor),
            limitPriceTextField.heightAnchor.constraint(equalToConstant: 44),
            
            executeButton.topAnchor.constraint(equalTo: limitPriceTextField.bottomAnchor, constant: 30),
            executeButton.leadingAnchor.constraint(equalTo: symbolTextField.leadingAnchor),
            executeButton.trailingAnchor.constraint(equalTo: symbolTextField.trailingAnchor),
            executeButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        symbolTextField.addTarget(self, action: #selector(symbolChanged), for: .editingChanged)
        orderTypeSegment.addTarget(self, action: #selector(orderTypeChanged), for: .valueChanged)
        executeButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
    }
    
    private func checkDeviceIntegrity() {
        let integrityResult = DeviceIntegrityManager.shared.performIntegrityChecks()
        
        if integrityResult.isCompromised {
            executeButton.isEnabled = false
            executeButton.backgroundColor = .systemGray
            
            let alert = UIAlertController(
                title: "Trading Disabled",
                message: "Trading is disabled due to device security concerns.",
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "OK", style: .default))
            present(alert, animated: true)
        }
    }
    
    @objc private func symbolChanged() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty else {
            currentPriceLabel.text = "Current Price: --"
            return
        }
        
        TradingService.shared.getStockQuote(symbol: symbol) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let stock):
                    self?.currentPriceLabel.text = "Current Price: $\(stock.currentPrice)"
                case .failure:
                    self?.currentPriceLabel.text = "Current Price: --"
                }
            }
        }
    }
    
    @objc private func orderTypeChanged() {
        limitPriceTextField.isHidden = orderTypeSegment.selectedSegmentIndex == 0
    }
    
    @objc private func executeTrade() {
        guard let symbol = symbolTextField.text, !symbol.isEmpty,
              let quantityString = quantityTextField.text,
              let quantity = Decimal(string: quantityString) else {
            showAlert(title: "Error", message: "Please enter valid symbol and quantity")
            return
        }
        
        let tradeType: TradeType = tradeTypeSegment.selectedSegmentIndex == 0 ? .buy : .sell
        let orderType: OrderType = orderTypeSegment.selectedSegmentIndex == 0 ? .market : .limit
        
        var limitPrice: Decimal?
        if orderType == .limit {
            guard let limitPriceString = limitPriceTextField.text,
                  let price = Decimal(string: limitPriceString) else {
                showAlert(title: "Error", message: "Please enter a valid limit price")
                return
            }
            limitPrice = price
        }
        
        let request = TradeRequest(
            symbol: symbol,
            type: tradeType,
            quantity: quantity,
            orderType: orderType,
            limitPrice: limitPrice
        )
        
        executeButton.isEnabled = false
        
        TradingService.shared.executeTrade(request: request) { [weak self] result in
            DispatchQueue.main.async {
                self?.executeButton.isEnabled = true
                
                switch result {
                case .success(let response):
                    self?.handleTradeSuccess(response)
                case .failure(let error):
                    self?.handleTradeError(error)
                }
            }
        }
    }
    
    private func handleTradeSuccess(_ response: TradeResponse) {
        let message = "Trade ID: \(response.tradeId)\nStatus: \(response.status.rawValue)\n\(response.message)"
        
        let alert = UIAlertController(title: "Trade Executed", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { [weak self] _ in
            self?.clearForm()
        })
        present(alert, animated: true)
    }
    
    private func handleTradeError(_ error: APIError) {
        var message = "Trade execution failed"
        
        switch error {
        case .deviceIntegrityCompromised(let details):
            message = "Security check failed:\n" + details.joined(separator: "\n")
        case .unauthorized:
            message = "Authentication required. Please log in again."
        default:
            message = "Trade execution failed. Please try again."
        }
        
        showAlert(title: "Error", message: message)
    }
    
    private func clearForm() {
        symbolTextField.text = ""
        quantityTextField.text = ""
        limitPriceTextField.text = ""
        currentPriceLabel.text = "Current Price: --"
        tradeTypeSegment.selectedSegmentIndex = 0
        orderTypeSegment.selectedSegmentIndex = 0
        limitPriceTextField.isHidden = true
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class TradeHistoryViewController: UIViewController {
    
    private var trades: [Trade] = []
    
    private let tableView: UITableView = {
        let table = UITableView()
        table.translatesAutoresizingMaskIntoConstraints = false
        return table
    }()
    
    private let refreshControl = UIRefreshControl()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadTradeHistory()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade History"
        
        view.addSubview(tableView)
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "TradeCell")
        tableView.refreshControl = refreshControl
        refreshControl.addTarget(self, action: #selector(refreshHistory), for: .valueChanged)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func loadTradeHistory() {
        TradingService.shared.getTradeHistory { [weak self] result in
            DispatchQueue.main.async {
                self?.refreshControl.endRefreshing()
                
                switch result {
                case .success(let trades):
                    self?.trades = trades
                    self?.tableView.reloadData()
                case .failure(let error):
                    self?.handleError(error)
                }
            }
        }
    }
    
    @objc private func refreshHistory() {
        loadTradeHistory()
    }
    
    private func handleError(_ error: APIError) {
        let message = "Failed to load trade history"
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension TradeHistoryViewController: UITableViewDelegate, UITableViewDataSource {
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return trades.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TradeCell", for: indexPath)
        let trade = trades[indexPath.row]
        
        let typeColor: UIColor = trade.type == .buy ? .systemGreen : .systemRed
        let typeText = trade.type.rawValue
        
        cell.textLabel?.text = "\(typeText) \(trade.quantity) \(trade.symbol) @ $\(trade.price)"
        cell.textLabel?.textColor = typeColor
        cell.detailTextLabel?.text = "Status: \(trade.status.rawValue)"
        
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        
        let trade = trades[indexPath.row]
        
        if trade.status == .pending {
            let alert = UIAlertController(
                title: "Cancel Trade?",
                message: "Do you want to cancel this pending trade?",
                preferredStyle: .alert
            )
            
            alert.addAction(UIAlertAction(title: "Cancel Trade", style: .destructive) { [weak self] _ in
                self?.cancelTrade(tradeId: trade.id)
            })
            
            alert.addAction(UIAlertAction(title: "Dismiss", style: .cancel))
            present(alert, animated: true)
        }
    }
    
    private func cancelTrade(tradeId: String) {
        TradingService.shared.cancelTrade(tradeId: tradeId) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success:
                    self?.loadTradeHistory()
                case .failure(let error):
                    self?.handleError(error)
                }
            }
        }
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        window = UIWindow(frame: UIScreen.main.bounds)
        
        let rootViewController: UIViewController
        if AuthenticationService.shared.isAuthenticated() {
            rootViewController = MainTabBarController()
        } else {
            rootViewController = LoginViewController()
        }
        
        window?.rootViewController = rootViewController
        window?.makeKeyAndVisible()
        
        return true
    }
}